{
  "permissions": {
    "allow": [
      "PowerShell(gh auth status 2>&1)",
      "PowerShell(node --version)",
      "PowerShell(npm --version)",
      "PowerShell(cd \"C:\\\\Users\\\\yaniv\"; $env:REPLICATE_API_TOKEN = \"r8_ZPe1GQtY3B8lyJAlqDJAjFjQTdCSRqv3i7rOC\"; node generate.mjs)",
      "Bash(git add *)",
      "Bash(git commit *)",
      "PowerShell(Get-ChildItem \"$env:USERPROFILE\\\\.claude\" -ErrorAction SilentlyContinue | Select-Object Name, PSIsContainer)",
      "WebFetch(domain:raw.githubusercontent.com)",
      "PowerShell(Get-ChildItem \"$env:USERPROFILE\\\\.claude\\\\skills\" -ErrorAction SilentlyContinue | Select-Object Name, PSIsContainer)",
      "PowerShell(Remove-Item \"$env:TEMP\\\\anthropics-skills\" -Recurse -Force)"
    ],
    "additionalDirectories": [
      "C:\\Users\\yaniv"
    ]
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "agent",
            "prompt": "You are a strict code quality reviewer. A file was just written or edited.\n\nEvent data: $ARGUMENTS\n\nInstructions:\n1. Parse the JSON. Get the file path from tool_input.file_path.\n2. Check the file extension. ONLY process these: .ts .tsx .js .jsx .py .go .rs .c .cpp .h .css .scss .java — skip everything else (JSON, markdown, config, lock files, images) and exit immediately.\n3. Read the file content.\n4. Scan for these issues and AUTO-FIX them if found:\n   a. console.log / console.error / console.warn calls — remove them entirely\n   b. Blocks of commented-out code (not explanatory comments, just dead code) — delete them\n   c. TypeScript `any` type — replace with `unknown` or a proper type\n   d. Obvious code duplication (3+ identical lines) — extract to a variable or helper\n5. For these issues, DO NOT auto-fix — add a comment ONLY if there is no comment already:\n   - Functions longer than ~30 lines (note: consider extracting)\n   - Magic numbers used in logic (note: consider naming as a constant)\n6. After each Edit you make, re-read the file to verify the fix looks correct and didn't introduce new issues.\n7. Repeat the scan-and-fix loop until a full scan finds no more auto-fixable issues.\n8. If you made no changes, do nothing and return silently.",
            "timeout": 120,
            "statusMessage": "Reviewing code quality..."
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Write",
        "hooks": [
          {
            "type": "command",
            "command": "$j = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; $f = $j.tool_input.file_path; if ($f -and (Test-Path $f -PathType Leaf)) { $d = Join-Path $PWD 'deletions'; New-Item -ItemType Directory -Force $d | Out-Null; $ts = Get-Date -Format 'yyyyMMdd_HHmmss'; $n = [IO.Path]::GetFileName($f); Copy-Item $f (Join-Path $d \"${ts}_$n\") -Force }; exit 0",
            "shell": "powershell",
            "statusMessage": "Backing up file before overwrite..."
          }
        ]
      },
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "$j = [System.Console]::In.ReadToEnd() | ConvertFrom-Json; $cmd = $j.tool_input.command; if ($cmd -match '\\brm\\b|\\bRemove-Item\\b') { $parts = $cmd -split '\\s+' | Where-Object { $_ -notmatch '^-' -and $_ -notin @('rm','Remove-Item','') }; foreach ($f in $parts) { if ($f -and (Test-Path $f -PathType Leaf)) { $d = Join-Path $PWD 'deletions'; New-Item -ItemType Directory -Force $d | Out-Null; $ts = Get-Date -Format 'yyyyMMdd_HHmmss'; $n = [IO.Path]::GetFileName($f); Copy-Item $f (Join-Path $d \"${ts}_$n\") -Force } } }; exit 0",
            "shell": "powershell",
            "statusMessage": "Backing up files before deletion..."
          }
        ]
      }
    ]
  },
  "fileCheckpointingEnabled": true
}

input.command:
$cleanSkills = @('thinking-patterns','decision-toolkit','cognitive-toolkit','tdd','release','lab-retro','retrospective','transcript-analyzer','tufte-report','meeting-processor','daydream')
$base = "$env:TEMP\glebis-skills"

foreach ($s in $cleanSkills) {
    $skillPath = Join-Path $base $s
    if (Test-Path $skillPath) {
        # Find SKILL.md inside
        $skillMd = Get-ChildItem $skillPath -Filter "SKILL.md" -Recurse | Select-Object -First 1
        if ($skillMd) { Write-Host "FOUND: $s -> $($skillMd.FullName)" }
        else { Write-Host "NO SKILL.md: $s" }
    } else {
        Write-Host "MISSING FOLDER: $s"
    }
}

# Find all SKILL.md files in alirezarezvani repo
$allSkillFiles = Get-ChildItem "$env:TEMP\alireza-skills" -Recurse -Filter "SKILL.md" |
    Where-Object { $_.FullName -notmatch '\\\.git\\' }

Write-Host "Total SKILL.md files found: $($allSkillFiles.Count)"
# Show sample paths
$allSkillFiles | Select-Object -First 10 | ForEach-Object {
    Write-Host $_.FullName.Replace("$env:TEMP\alireza-skills\", "")
}

$allSkillFiles = Get-ChildItem "$env:TEMP\alireza-skills" -Recurse -Filter "SKILL.md" |
    Where-Object { $_.FullName -notmatch '\\\.git\\' }

# Find Claude Code specific skills - NOT in .gemini, .codex, .vibe, .hermes paths
$claudeSkills = $allSkillFiles | Where-Object {
    $_.FullName -notmatch '\\\.gemini\\' -and
    $_.FullName -notmatch '\\\.codex\\' -and
    $_.FullName -notmatch '\\\.vibe\\' -and
    $_.FullName -notmatch '\\\.hermes\\' -and
    $_.FullName -notmatch '\\\.cursor\\' -and
    $_.FullName -notmatch '\\node_modules\\'
}

Write-Host "Claude Code skills: $($claudeSkills.Count)"
$claudeSkills | Select-Object -First 20 | ForEach-Object {
    Write-Host $_.FullName.Replace("$env:TEMP\alireza-skills\", "")
}

$allSkillFiles = Get-ChildItem "$env:TEMP\alireza-skills" -Recurse -Filter "SKILL.md" |
    Where-Object { 
        $_.FullName -notmatch '\\\.gemini\\' -and
        $_.FullName -notmatch '\\\.codex\\' -and
        $_.FullName -notmatch '\\\.vibe\\' -and
        $_.FullName -notmatch '\\\.hermes\\' -and
        $_.FullName -notmatch '\\\.cursor\\' -and
        $_.FullName -notmatch '\\node_modules\\'
    }

$skillsDir = "$env:USERPROFILE\.claude\skills"

$conflicts = @()
$newSkills = @()

foreach ($f in $allSkillFiles) {
    $skillName = $f.Directory.Name  # parent folder = skill name
    $targetPath = Join-Path $skillsDir "$skillName.md"
    if (Test-Path $targetPath) {
        $conflicts += $skillName
    } else {
        $newSkills += @{ name = $skillName; path = $f.FullName }
    }
}

Write-Host "New skills (no conflict): $($newSkills.Count)"
Write-Host "Conflicts: $($conflicts.Count)"
Write-Host ""
Write-Host "=== CONFLICTS ==="
$conflicts | Sort-Object | ForEach-Object { Write-Host "  $_" }

# Find the conflicting files in alireza repo
$conflictFiles = Get-ChildItem "$env:TEMP\alireza-skills" -Recurse -Filter "SKILL.md" |
    Where-Object { 
        $_.Directory.Name -in @('brand-guidelines','internal-comms') -and
        $_.FullName -notmatch '\\\.gemini\\' -and
        $_.FullName -notmatch '\\\.codex\\'
    }
$conflictFiles | ForEach-Object { Write-Host $_.FullName }

