# Fetch the actual skill from GitHub API
$resp = Invoke-RestMethod -Uri "https://api.github.com/repos/davila7/claude-code-templates/contents/cli-tool/components/skills/development/code-reviewer" -Headers @{ 'User-Agent' = 'claude-code-templates' } -UseBasicParsing
$resp | ForEach-Object { Write-Host "$($_.name) ($($_.type)) - $($_.size) bytes" }

# Check for conflicts with existing skills
$names = @('code-reviewer','code-review','pr-review','adversarial-reviewer','karpathy-reviewer')
$dir = "$env:USERPROFILE\.claude\skills"
foreach ($n in $names) {
    if (Test-Path (Join-Path $dir "$n.md")) { Write-Host "EXISTS: $n.md" }
}
# Clean up temp
Remove-Item "$env:TEMP\cct-inspect" -Recurse -Force -ErrorAction SilentlyContinue
Remove-Item "$env:TEMP\cct.tgz" -Force -ErrorAction SilentlyContinue
Write-Host "Temp cleaned"

