import {
  AbsoluteFill,
  Sequence,
  useCurrentFrame,
  useVideoConfig,
  interpolate,
  spring,
  Easing,
} from "remotion";
import { StatsRow } from "./components/StatsRow";
import { LineChart } from "./components/LineChart";
import { BarChart } from "./components/BarChart";
import { CtaScene } from "./components/CtaScene";
import { SceneFade } from "./components/SceneFade";

const SCENE_DURATIONS = {
  intro: 120,      // 0–4s
  stats: 180,      // 4–10s
  lineChart: 210,  // 10–17s
  barChart: 210,   // 17–24s
  cta: 180,        // 24–30s
} as const;

const STARTS = {
  intro: 0,
  stats: 120,
  lineChart: 300,
  barChart: 510,
  cta: 720,
};

const PALETTE = {
  bg: "#0F172A",
  surface: "#1E293B",
  border: "#334155",
  accent: "#38BDF8",
  accentGreen: "#34D399",
  accentOrange: "#FB923C",
  textPrimary: "#F1F5F9",
  textMuted: "#94A3B8",
};

export const ApiDashboardDemo: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  return (
    <AbsoluteFill style={{ background: PALETTE.bg, fontFamily: "'Inter', sans-serif" }}>
      {/* Persistent subtle grid background */}
      <GridBackground />

      {/* Scene 1: Intro title */}
      <Sequence from={STARTS.intro} durationInFrames={SCENE_DURATIONS.intro + 30}>
        <SceneFade duration={20} outStart={SCENE_DURATIONS.intro}>
          <IntroScene fps={fps} />
        </SceneFade>
      </Sequence>

      {/* Scene 2: Stats cards */}
      <Sequence from={STARTS.stats} durationInFrames={SCENE_DURATIONS.stats + 30}>
        <SceneFade duration={20} outStart={SCENE_DURATIONS.stats}>
          <DashboardLayout title="API Overview">
            <StatsRow fps={fps} />
          </DashboardLayout>
        </SceneFade>
      </Sequence>

      {/* Scene 3: Latency line chart */}
      <Sequence from={STARTS.lineChart} durationInFrames={SCENE_DURATIONS.lineChart + 30}>
        <SceneFade duration={20} outStart={SCENE_DURATIONS.lineChart}>
          <DashboardLayout title="Response Latency (ms)">
            <LineChart fps={fps} />
          </DashboardLayout>
        </SceneFade>
      </Sequence>

      {/* Scene 4: Request volume bar chart */}
      <Sequence from={STARTS.barChart} durationInFrames={SCENE_DURATIONS.barChart + 30}>
        <SceneFade duration={20} outStart={SCENE_DURATIONS.barChart}>
          <DashboardLayout title="Requests per Minute">
            <BarChart fps={fps} />
          </DashboardLayout>
        </SceneFade>
      </Sequence>

      {/* Scene 5: CTA */}
      <Sequence from={STARTS.cta} durationInFrames={SCENE_DURATIONS.cta}>
        <SceneFade duration={20} outStart={SCENE_DURATIONS.cta - 20}>
          <CtaScene fps={fps} />
        </SceneFade>
      </Sequence>
    </AbsoluteFill>
  );
};

const GridBackground: React.FC = () => (
  <AbsoluteFill
    style={{
      backgroundImage:
        "linear-gradient(rgba(51,65,85,0.3) 1px, transparent 1px), linear-gradient(90deg, rgba(51,65,85,0.3) 1px, transparent 1px)",
      backgroundSize: "60px 60px",
      opacity: 0.4,
    }}
  />
);

type DashboardLayoutProps = { title: string; children: React.ReactNode };

const DashboardLayout: React.FC<DashboardLayoutProps> = ({ title, children }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const titleY = interpolate(frame, [0, 20], [20, 0], {
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
  const titleOpacity = interpolate(frame, [0, 20], [0, 1], { extrapolateRight: "clamp" });

  return (
    <AbsoluteFill style={{ padding: "60px 80px" }}>
      {/* Header bar */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 16,
          marginBottom: 48,
          opacity: titleOpacity,
          transform: `translateY(${titleY}px)`,
        }}
      >
        <div
          style={{
            width: 6,
            height: 32,
            borderRadius: 3,
            background: "linear-gradient(180deg, #38BDF8, #818CF8)",
          }}
        />
        <span style={{ fontSize: 28, fontWeight: 700, color: "#F1F5F9", letterSpacing: "-0.5px" }}>
          {title}
        </span>
        <div style={{ marginLeft: "auto", display: "flex", gap: 8, alignItems: "center" }}>
          <div style={{ width: 8, height: 8, borderRadius: "50%", background: "#34D399" }} />
          <span style={{ fontSize: 14, color: "#94A3B8" }}>Live</span>
        </div>
      </div>
      {children}
    </AbsoluteFill>
  );
};

type IntroSceneProps = { fps: number };

const IntroScene: React.FC<IntroSceneProps> = ({ fps }) => {
  const frame = useCurrentFrame();

  const logoScale = spring({ frame, fps, config: { damping: 14, stiffness: 100 } });
  const subtitleOpacity = interpolate(frame, [20, 50], [0, 1], { extrapolateRight: "clamp" });
  const subtitleY = interpolate(frame, [20, 50], [16, 0], {
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });

  return (
    <AbsoluteFill
      style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 24 }}
    >
      <div
        style={{
          transform: `scale(${logoScale})`,
          display: "flex",
          alignItems: "center",
          gap: 20,
        }}
      >
        <div
          style={{
            width: 64,
            height: 64,
            borderRadius: 16,
            background: "linear-gradient(135deg, #38BDF8, #818CF8)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 32,
          }}
        >
          ⚡
        </div>
        <span style={{ fontSize: 56, fontWeight: 800, color: "#F1F5F9", letterSpacing: "-2px" }}>
          API<span style={{ color: "#38BDF8" }}>Dashboard</span>
        </span>
      </div>
      <div
        style={{
          opacity: subtitleOpacity,
          transform: `translateY(${subtitleY}px)`,
          fontSize: 22,
          color: "#94A3B8",
          letterSpacing: "0.5px",
        }}
      >
        Real-time monitoring · Analytics · Alerts
      </div>
    </AbsoluteFill>
  );
};

