import { AbsoluteFill, useCurrentFrame, spring, interpolate } from "remotion";

type CtaSceneProps = { fps: number };

const METRICS = [
  { icon: "✓", text: "99.98% uptime SLA" },
  { icon: "✓", text: "42ms average latency" },
  { icon: "✓", text: "12,840 req/min peak throughput" },
  { icon: "✓", text: "0.04% error rate" },
];

const METRIC_STAGGER = 12;
const METRIC_ENTRY_DELAY = 40;

export const CtaScene: React.FC<CtaSceneProps> = ({ fps }) => {
  const frame = useCurrentFrame();

  const headingScale = spring({ frame, fps, config: { damping: 14, stiffness: 100 } });
  const ctaOpacity = interpolate(frame, [80, 110], [0, 1], { extrapolateRight: "clamp" });
  const ctaY = interpolate(frame, [80, 110], [20, 0], { extrapolateRight: "clamp" });

  return (
    <AbsoluteFill
      style={{
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 48,
        padding: "0 160px",
      }}
    >
      <div style={{ transform: `scale(${headingScale})`, textAlign: "center" }}>
        <div style={{ fontSize: 52, fontWeight: 800, color: "#F1F5F9", letterSpacing: "-1.5px", lineHeight: 1.1 }}>
          Production-ready{" "}
          <span
            style={{
              background: "linear-gradient(90deg, #38BDF8, #818CF8)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
            }}
          >
            from day one
          </span>
        </div>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 20, width: "100%", maxWidth: 700 }}>
        {METRICS.map((m, i) => {
          const delay = METRIC_ENTRY_DELAY + i * METRIC_STAGGER;
          const itemOpacity = interpolate(frame - delay, [0, 20], [0, 1], {
            extrapolateRight: "clamp",
            extrapolateLeft: "clamp",
          });
          const itemX = interpolate(frame - delay, [0, 20], [-24, 0], {
            extrapolateRight: "clamp",
            extrapolateLeft: "clamp",
          });

          return (
            <div
              key={m.text}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 20,
                opacity: itemOpacity,
                transform: `translateX(${itemX}px)`,
              }}
            >
              <div
                style={{
                  width: 32,
                  height: 32,
                  borderRadius: "50%",
                  background: "#34D399",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 16,
                  fontWeight: 700,
                  color: "#0F172A",
                  flexShrink: 0,
                }}
              >
                {m.icon}
              </div>
              <span style={{ fontSize: 22, color: "#CBD5E1" }}>{m.text}</span>
            </div>
          );
        })}
      </div>

      <div style={{ opacity: ctaOpacity, transform: `translateY(${ctaY}px)` }}>
        <div
          style={{
            background: "linear-gradient(135deg, #38BDF8, #818CF8)",
            borderRadius: 14,
            padding: "20px 52px",
            fontSize: 22,
            fontWeight: 700,
            color: "#0F172A",
            letterSpacing: "0.5px",
          }}
        >
          Start Free → api.example.com/docs
        </div>
      </div>
    </AbsoluteFill>
  );
};

