import { SceneFade } from "./components/SceneFade";

const SCENE_DURATIONS = {
  intro: 120,      // 0–4s
  stats: 180,      // 4–10s
  lineChart: 210,  // 10–17s
  barChart: 210,   // 17–24s
  cta: 180,        // 24–30s
} as const;

const STARTS = {
  intro: 0,
  stats: 120,
  lineChart: 300,
  barChart: 510,
  cta: 720,
};

const PALETTE = {
  bg: "#0F172A",
  surface: "#1E293B",
  border: "#334155",
  accent: "#38BDF8",
  accentGreen: "#34D399",
  accentOrange: "#FB923C",
  textPrimary: "#F1F5F9",
  textMuted: "#94A3B8",
};

